} satisfies IGraphData;

const getter: GraphDataGetter = () => graphData;

describe('core/plugins/graphQuery/subgraph', () => {
  it('returns an empty graph for missing nodes or negative hops', () => {
    expect(buildSubgraph('missing.ts', 1, getter)).toEqual({ nodes: [], edges: [] });
    expect(buildSubgraph('a.ts', -1, getter)).toEqual({ nodes: [], edges: [] });
  });

  it('returns the induced subgraph around the requested node', () => {
    expect(buildSubgraph('b.ts', 1, getter)).toEqual({
      nodes: [
        { id: 'a.ts', label: 'a.ts', color: '#fff' },
        { id: 'b.ts', label: 'b.ts', color: '#fff' },
        { id: 'c.ts', label: 'c.ts', color: '#fff' },
      ],
      edges: [
        { id: 'a-b', from: 'a.ts', to: 'b.ts', kind: 'import', sources: [] },
        { id: 'b-c', from: 'b.ts', to: 'c.ts', kind: 'import', sources: [] },
      ],
    });
  });
});

import { describe, expect, it } from 'vitest';
import type { IGraphData } from '../../../../src/shared/graph/types';
import { getEdgesByKeys, getGraphIndex } from '../../../../src/core/plugins/graphQuery/cache';

const graph: IGraphData = {
  nodes: [
    { id: 'a', label: 'a', color: '#fff' },
    { id: 'b', label: 'b', color: '#fff' },
  ],
  edges: [
    { id: 'a-b', from: 'a', to: 'b', kind: 'import', sources: [] },
    { id: 'skip', from: 'a', to: 'missing', kind: 'reference', sources: [] },
  ],
};

describe('core/plugins/graphQuery/cache', () => {
  it('indexes only edges whose endpoints exist in the graph', () => {
    const index = getGraphIndex(graph);

    expect(index.nodeById.get('a')?.id).toBe('a');
    expect(index.graph.getNodeAttributes('a')).toEqual({ node: graph.nodes[0] });
    expect(index.graph.getEdgeAttributes('a-b')).toEqual({ edge: graph.edges[0] });
    expect(index.edgeById.has('a-b')).toBe(true);
    expect(index.edgeById.has('skip')).toBe(false);
  });

  it('returns indexed edges by key and ignores missing ones', () => {
    const index = getGraphIndex(graph);

    expect(getEdgesByKeys(['a-b', 'missing'], index.edgeById)).toEqual([
      { id: 'a-b', from: 'a', to: 'b', kind: 'import', sources: [] },
    ]);
  });

  it('reuses the cached index for the same graph object', () => {
    const first = getGraphIndex(graph);
    const second = getGraphIndex(graph);

    expect(second).toBe(first);
  });
});

import { describe, expect, it } from 'vitest';
import { findNodePath } from '../../../../src/core/plugins/graphQuery/path';
import type { GraphDataGetter } from '../../../../src/core/plugins/graphQuery/facade';
import type { IGraphData } from '../../../../src/shared/graph/types';

const graphData = {
  nodes: [
    { id: 'a.ts', label: 'a.ts', color: '#fff' },
    { id: 'b.ts', label: 'b.ts', color: '#fff' },
    { id: 'c.ts', label: 'c.ts', color: '#fff' },
  ],
  edges: [
    { id: 'a-b', from: 'a.ts', to: 'b.ts', kind: 'import', sources: [] },
    { id: 'b-c', from: 'b.ts', to: 'c.ts', kind: 'import', sources: [] },
  ],
} satisfies IGraphData;

const getter: GraphDataGetter = () => graphData;

describe('core/plugins/graphQuery/path', () => {
  it('returns null when either endpoint is missing', () => {
    expect(findNodePath('missing.ts', 'c.ts', getter)).toBeNull();
    expect(findNodePath('a.ts', 'missing.ts', getter)).toBeNull();
  });

  it('returns null when no directed path exists', () => {
    expect(findNodePath('c.ts', 'a.ts', getter)).toBeNull();
  });

  it('returns the path nodes when reachable', () => {
    expect(findNodePath('a.ts', 'c.ts', getter)?.map((node) => node.id)).toEqual([
      'a.ts',
      'b.ts',
      'c.ts',
    ]);
  });

  it('returns the starting node when the source and target are the same', () => {
    expect(findNodePath('a.ts', 'a.ts', getter)?.map((node) => node.id)).toEqual([
      'a.ts',
    ]);
  });

  it('handles cycles without revisiting nodes indefinitely', () => {
    const cyclicGetter: GraphDataGetter = () => ({
      nodes: [
        { id: 'a.ts', label: 'a.ts', color: '#fff' },
        { id: 'b.ts', label: 'b.ts', color: '#fff' },
        { id: 'c.ts', label: 'c.ts', color: '#fff' },
      ],
      edges: [
        { id: 'a-b', from: 'a.ts', to: 'b.ts', kind: 'import', sources: [] },
        { id: 'b-a', from: 'b.ts', to: 'a.ts', kind: 'import', sources: [] },
        { id: 'b-c', from: 'b.ts', to: 'c.ts', kind: 'import', sources: [] },
      ],
    });

    expect(findNodePath('a.ts', 'c.ts', cyclicGetter)?.map((node) => node.id)).toEqual([
      'a.ts',
      'b.ts',
      'c.ts',
    ]);
  });
});

